scripts.script:
function series() {
  var out = []
  var v = 100
  for (var i = 0; i < 60; i++) {
    v += 2 + Math.sin(i / 5) * 3
    out.push([i, Math.round(v)])
  }
  return out
}

html.div:
Clear The ruler tool is pre-selected in the toolbar. Drag from A to B on the chart.
{{ charts[0] }}
The ruler is a built-in toolbar tool, pre-selected here with toolbar.autoSelected: 'measure'. Drag across the plot: a shaded band spans the two points and a readout shows the change, the % change and the range between them, with the endpoints snapped to the price line (the finance-style default, measure.mode: 'span'). Green means the move is up, red means down. Release to pin it; a pinned ruler is stored in data coordinates, so it stays glued when you zoom or resize. Click the ruler icon again to deselect it and hand the plot back to zoom; the m key still works too. Fires the measured event. Set measure.mode: 'free' for a diagonal ruler between any two points. Needs the measure feature. Clear removes all rulers.

vanilla-js-script:
// The ruler tool is pre-selected via toolbar.autoSelected: 'measure', so the
// plot is already armed on load -- just drag. The toolbar icon toggles it (and
// the 'm' key still works); no custom wiring needed here.
var readout = document.getElementById('mz-readout')

document.getElementById('mz-clear').addEventListener('click', function () {
  chart.clearMeasures()
})

chart.addEventListener('measured', function (c, o) {
  readout.textContent =
    'dx=' + Number(o.dx).toFixed(2) +
    '  dy=' + Number(o.dy).toFixed(2) +
    '  (' + (o.percentChange >= 0 ? '+' : '') + Number(o.percentChange).toFixed(1) + '%)'
})
